starterCode.javascript:
function useMemoizedArray(array, dependencyArray) {
  const memoizedArray = useMemo(() => {
    return array.map((item, index) => ({ ...item, id: index }));
  }, [dependencyArray]);
  return memoizedArray;
}

export default useMemoizedArray;

starterCode.python:
class Solution:
  def __init__(self):
    pass

  def useMemoizedArray(self, array, dependencyArray):
    memoizedArray = self.memoizedArray(array, dependencyArray)
    return memoizedArray

  def memoizedArray(self, array, dependencyArray):
    return [dict(item, id=index) for index, item in enumerate(array)]

  def main(self):
    array = [{"id": 1, "name": "John"}, {"id": 2, "name": "Jane"}]
    dependencyArray = [{"id": 1, "name": "John"}, {"id": 2, "name": "Jane"}]
    self.useMemoizedArray(array, dependencyArray)

if __name__ == '__main__':
  solution = Solution()
  solution.main()

